INSERT INTO audio_conversations (id, section_part, title, audio_url, transcript, is_active) VALUES
('a0000009-0001-4000-8000-000000000001', 'A', 'Lost ID Card', '', E'Man: I can''t find my student ID anywhere. I''ve checked my dorm and the library.\nWoman: If you can''t find it by tomorrow, you''ll have to pay twenty dollars for a replacement at the registrar.\nMan: I guess I''ll retrace my steps one more time.', TRUE),
('a0000009-0001-4000-8000-000000000002', 'A', 'Group Study', '', E'Woman: Are we still meeting at the cafe to study for the economics midterm?\nMan: The cafe is usually too noisy on Thursday evenings. Why don''t we book a study room in the library instead?\nWoman: Good idea, I''ll reserve one online right now.', TRUE),
('a0000009-0001-4000-8000-000000000003', 'A', 'Laptop Issue', '', E'Man: My laptop keeps shutting down every time I open the statistical analysis software.\nWoman: You should take it to the IT help desk in the student center. They fixed a similar issue for me last semester.\nMan: I hope they can do it before my assignment is due on Friday.', TRUE),
('a0000009-0001-4000-8000-000000000004', 'A', 'Traffic Jam', '', E'Woman: I''m so sorry I''m late. There was a major accident on the highway and traffic was backed up for miles.\nMan: Don''t worry, the professor hasn''t started the lecture yet. She''s still setting up the projector.\nWoman: That''s a relief, I thought I missed the introduction.', TRUE),
('a0000009-0001-4000-8000-000000000005', 'A', 'Dropping a Class', '', E'Man: I''m thinking about dropping out of Professor Miller''s physics class. I just can''t keep up with the reading.\nWoman: The deadline to drop without a penalty on your transcript was yesterday.\nMan: You''re kidding! I guess I''ll have to talk to him about getting some extra help.', TRUE),
('a0000009-0001-4000-8000-000000000006', 'A', 'Movie Night', '', E'Woman: Do you want to go see that new documentary about climate change tonight?\nMan: I''d love to, but I have a shift at the bookstore covering for Sarah.\nWoman: Too bad. Maybe we can catch it this weekend if it''s still playing.', TRUE),
('a0000009-0001-4000-8000-000000000007', 'A', 'Printer Broken', '', E'Man: Excuse me, the printer in the corner seems to be jammed again.\nWoman: Thanks for letting me know. I''ll put an out-of-order sign on it and call maintenance.\nMan: Is there another one I can use to print my essay?', TRUE),
('a0000009-0001-4000-8000-000000000008', 'A', 'Flight Delay', '', E'Woman: I just got a text that my flight home for Thanksgiving is delayed by three hours.\nMan: Well, look on the bright side. Now you have plenty of time to finish reading that novel for literature class.\nWoman: I suppose you''re right, but I was really looking forward to getting home early.', TRUE),
('a0000009-0001-4000-8000-000000000009', 'A', 'Coffee Shop', '', E'Man: Can I get a large iced coffee with a shot of vanilla, please?\nWoman: I''m sorry, our ice machine is broken right now. We only have hot beverages available.\nMan: Oh, in that case, just a hot cappuccino will do.', TRUE),
('a0000009-0001-4000-8000-000000000010', 'A', 'Art History Essay', '', E'Woman: How is your essay on Renaissance art coming along?\nMan: It''s going slowly. I''ve spent hours researching, but I still don''t have a clear thesis statement.\nWoman: Why don''t you show me your outline? Sometimes bouncing ideas off someone helps clarify things.', TRUE);
INSERT INTO questions (id, section, part, question_text, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, topic_tags, conversation_group_id, question_order_in_group, is_active) VALUES
('d1000009-0001-4000-8000-000000000001', 1, 'A', 'What will the man likely do next?', 'Pay twenty dollars immediately', 'Search for his ID card again', 'Go to the registrar''s office tomorrow', 'Borrow an ID from a friend', 'B', 'The man says "I guess I''ll retrace my steps one more time."', 2, ARRAY['inference','campus_life'], 'a0000009-0001-4000-8000-000000000001', 1, TRUE),
('d1000009-0001-4000-8000-000000000002', 1, 'A', 'What does the man suggest?', 'Meeting at the cafe earlier', 'Studying on Friday instead', 'Booking a room in the library', 'Canceling the study session', 'C', 'The man suggests booking a study room in the library because the cafe is too noisy.', 2, ARRAY['suggestion','academic'], 'a0000009-0001-4000-8000-000000000002', 1, TRUE),
('d1000009-0001-4000-8000-000000000003', 1, 'A', 'What does the woman advise the man to do?', 'Buy a new laptop before Friday', 'Take the computer to the IT help desk', 'Uninstall the statistical software', 'Ask the professor for an extension', 'B', 'The woman advises him to take it to the IT help desk in the student center.', 2, ARRAY['suggestion','campus_life'], 'a0000009-0001-4000-8000-000000000003', 1, TRUE),
('d1000009-0001-4000-8000-000000000004', 1, 'A', 'Why is the woman relieved?', 'The accident on the highway was cleared', 'The professor has not begun the lecture yet', 'She fixed the projector for the professor', 'She did not miss the entire class', 'B', 'The woman is relieved because the man tells her the professor hasn''t started the lecture yet.', 2, ARRAY['cause_effect','academic'], 'a0000009-0001-4000-8000-000000000004', 1, TRUE),
('d1000009-0001-4000-8000-000000000005', 1, 'A', 'What does the woman mean?', 'The man should read faster', 'The man cannot drop the class without a penalty now', 'The deadline was extended until yesterday', 'Professor Miller is strict about reading', 'B', 'The woman implies it is too late to drop without a penalty by stating the deadline was yesterday.', 2, ARRAY['inference','academic'], 'a0000009-0001-4000-8000-000000000005', 1, TRUE),
('d1000009-0001-4000-8000-000000000006', 1, 'A', 'Why can''t the man go to the movie?', 'He does not like documentaries', 'He has already seen it', 'He has to work at the bookstore', 'He needs to study with Sarah', 'C', 'The man says he has a shift at the bookstore covering for Sarah.', 1, ARRAY['detail','campus_life'], 'a0000009-0001-4000-8000-000000000006', 1, TRUE),
('d1000009-0001-4000-8000-000000000007', 1, 'A', 'What will the woman do?', 'Print the essay for the man', 'Fix the jammed printer herself', 'Put up a sign and call for repairs', 'Show the man how to use another printer', 'C', 'The woman says she will "put an out-of-order sign on it and call maintenance."', 2, ARRAY['detail','campus_life'], 'a0000009-0001-4000-8000-000000000007', 1, TRUE),
('d1000009-0001-4000-8000-000000000008', 1, 'A', 'What is the man''s attitude toward the delay?', 'He is angry about it', 'He sees a positive aspect to it', 'He is worried she will miss Thanksgiving', 'He thinks the airline should apologize', 'B', 'He tells her to "look on the bright side" and that she can use the time to read.', 3, ARRAY['attitude','emotion'], 'a0000009-0001-4000-8000-000000000008', 1, TRUE),
('d1000009-0001-4000-8000-000000000009', 1, 'A', 'What does the man order?', 'A large iced coffee', 'A hot cappuccino', 'A cold vanilla beverage', 'He decides not to order anything', 'B', 'Because the ice machine is broken, he changes his order to a hot cappuccino.', 1, ARRAY['detail','campus_life'], 'a0000009-0001-4000-8000-000000000009', 1, TRUE),
('d1000009-0001-4000-8000-000000000010', 1, 'A', 'What does the woman offer to do?', 'Write the thesis statement for him', 'Listen to his ideas and review his outline', 'Share her research on Renaissance art', 'Give him her essay to copy', 'B', 'The woman suggests he show her his outline and says "bouncing ideas off someone helps."', 2, ARRAY['suggestion','academic'], 'a0000009-0001-4000-8000-000000000010', 1, TRUE);
INSERT INTO audio_conversations (id, section_part, title, audio_url, transcript, is_active) VALUES
('a0000009-0002-4000-8000-000000000001', 'B', 'Changing Majors', '',
INSERT INTO questions (id, section, part, question_text, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, topic_tags, conversation_group_id, question_order_in_group, is_active) VALUES
('d1000009-0002-4000-8000-000000000001', 1, 'B', 'What has the woman recently done?', 'Passed her biology exam', 'Changed her major to journalism', 'Dropped a biology class', 'Told her father she wants to be a writer', 'C', 'She says "I actually dropped that class" referring to biology.', 2, ARRAY['detail','academic'], 'a0000009-0002-4000-8000-000000000001', 1, TRUE),
('d1000009-0002-4000-8000-000000000002', 1, 'B', 'Why does the woman want to change her major?', 'She failed her pre-med prerequisite classes', 'She enjoyed working for the campus newspaper', 'The biology professor advised her to do so', 'Her father suggested journalism', 'B', 'She says she spent the summer writing for the campus newspaper and loved it.', 2, ARRAY['cause_effect','academic'], 'a0000009-0002-4000-8000-000000000001', 2, TRUE),
('d1000009-0002-4000-8000-000000000003', 1, 'B', 'What will happen to the science credits she already earned?', 'They will be completely discarded', 'They will cover her general education electives', 'She will have to retake them as journalism credits', 'They will count toward a minor in biology', 'B', 'She mentions the advisor told her they will cover all her general education electives.', 3, ARRAY['detail','academic_advising'], 'a0000009-0002-4000-8000-000000000001', 3, TRUE),
('d1000009-0002-4000-8000-000000000004', 1, 'B', 'Why is the woman nervous about calling her father?', 'He wanted her to become a doctor', 'She needs to ask him for more money', 'He is paying for her tuition', 'He does not believe journalism is a real major', 'A', 'She says her dad wanted her to be a doctor like him.', 2, ARRAY['inference','emotion'], 'a0000009-0002-4000-8000-000000000001', 4, TRUE),
('d1000009-0002-4000-8000-000000000005', 1, 'B', 'What is the main problem the man is facing?', 'He lost the budget for the festival', 'The main band canceled their performance', 'Nobody bought tickets for the festival', 'It is predicted to rain on the day of the event', 'B', 'The man says "the main band we booked had to cancel due to illness."', 2, ARRAY['main_idea','campus_life'], 'a0000009-0002-4000-8000-000000000002', 1, TRUE),
('d1000009-0002-4000-8000-000000000006', 1, 'B', 'What is the committee''s solution to the music problem?', 'To cancel the festival entirely', 'To have a DJ play music instead', 'To hire a local jazz ensemble', 'To ask students to perform', 'C', 'The man states they decided "to hire a local Jazz ensemble instead."', 2, ARRAY['detail','campus_life'], 'a0000009-0002-4000-8000-000000000002', 2, TRUE),
('d1000009-0002-4000-8000-000000000007', 1, 'B', 'Why hasn''t the administration approved the barbecue grills yet?', 'They are reviewing strict fire safety regulations', 'They want the students to pay an extra fee', 'They prefer the food trucks', 'They lost the paperwork', 'A', 'The man explains there are strict fire safety regulations they are reviewing.', 3, ARRAY['detail','campus_life'], 'a0000009-0002-4000-8000-000000000002', 3, TRUE),
('d1000009-0002-4000-8000-000000000008', 1, 'B', 'What will happen if the permits are not approved by Friday?', 'The festival will be postponed', 'They will rely on pre-packaged sandwiches', 'They will move the festival indoors', 'They will hire different food trucks', 'B', 'The man says if they aren''t approved, "we''ll have to rely on pre-packaged sandwiches."', 2, ARRAY['cause_effect','campus_life'], 'a0000009-0002-4000-8000-000000000002', 4, TRUE);
INSERT INTO audio_conversations (id, section_part, title, audio_url, transcript, is_active) VALUES
('a0000009-0003-4000-8000-000000000001', 'C', 'History of the Bicycle', '',
INSERT INTO questions (id, section, part, question_text, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, topic_tags, conversation_group_id, question_order_in_group, is_active) VALUES
('d1000009-0003-4000-8000-000000000001', 1, 'C', 'What is the main topic of the lecture?', 'The invention of the rubber tire', 'The dangers of early transportation', 'The evolution of bicycle design', 'How to ride a penny-farthing', 'C', 'The professor introduces the lecture by stating they will discuss "the fascinating evolution of a machine... the bicycle."', 2, ARRAY['main_idea','lecture'], 'a0000009-0003-4000-8000-000000000001', 1, TRUE),
('d1000009-0003-4000-8000-000000000002', 1, 'C', 'How did riders move the earliest bicycle, the draisine?', 'By turning pedals on the front wheel', 'By using a chain drive mechanism', 'By pushing their feet against the ground', 'By pulling a lever on the handlebars', 'C', 'The professor explains that the draisine had no pedals and riders pushed their feet against the ground.', 2, ARRAY['detail','lecture'], 'a0000009-0003-4000-8000-000000000001', 2, TRUE),
('d1000009-0003-4000-8000-000000000003', 1, 'C', 'Why was the velocipede called the "boneshaker"?', 'Its wheels often broke', 'It was extremely heavy', 'Its iron tires on cobblestone roads made for an uncomfortable ride', 'Riders frequently fell off', 'C', 'The lecture states that because of the solid wood frame and iron tires, riding on cobblestones was very uncomfortable, earning it the nickname "boneshaker."', 2, ARRAY['cause_effect','lecture'], 'a0000009-0003-4000-8000-000000000001', 3, TRUE),
('d1000009-0003-4000-8000-000000000004', 1, 'C', 'What major improvement did the "safety bicycle" introduce?', 'A larger front wheel for speed', 'An iron frame for durability', 'A chain drive to the rear wheel', 'The removal of pedals', 'C', 'The safety bicycle featured "a chain drive connecting the pedals to the rear wheel," making it stable and comfortable.', 3, ARRAY['detail','lecture'], 'a0000009-0003-4000-8000-000000000001', 4, TRUE);
